function runUserCommand(command) {
  return new Promise((resolve, reject) => {
    // Reject dangerous characters and validate command
    if (typeof command !== 'string' || /[;&|`$()]/.test(command)) {
      reject(new Error('Invalid command'));
      return;
    }

    // Use shell: false and pass arguments as array to prevent injection
    const { spawn } = require('child_process');
    const [cmd, ...args] = command.split(' ').filter(Boolean);

    // Whitelist allowed commands
    const allowedCommands = ['ls', 'pwd', 'echo', 'cat'];
    if (!allowedCommands.includes(cmd)) {
      reject(new Error('Command not allowed'));
      return;
    }

    const child = spawn(cmd, args, { shell: false });
    let stdout = '';
    let stderr = '';

    child.stdout.on('data', (data) => {
      stdout += data.toString();
    });

    child.stderr.on('data', (data) => {
      stderr += data.toString();
    });

    child.on('error', (error) => {
      reject(error);
    });

    child.on('close', (code) => {
      if (code !== 0) {
        reject(new Error(`Command failed with code ${code}`));
        return;
      }
      resolve({ stdout, stderr });
    });
  });
}

