async function callExternalApi(url, method = 'GET', body = null, authToken = null) {
  const headers = {
    'Content-Type': 'application/json',
  };

  if (authToken) {
    headers['Authorization'] = `Bearer ${authToken}`;
  }

  const options = {
    method,
    headers,
  };

  if (body && (method === 'POST' || method === 'PUT' || method === 'PATCH')) {
    options.body = JSON.stringify(body);
  }

  try {
    const response = await fetch(url, options);

    if (!response.ok) {
      const errorData = await response.json().catch(() => response.text());
      throw new Error(`API call failed with status ${response.status}: ${JSON.stringify(errorData)}`);
    }

    try {
      const contentType = response.headers.get('content-type');
      if (contentType && contentType.includes('application/json')) {
        return await response.json();
      } else {
        return await response.text();
      }
    } catch (e) {
      // If content-type is not JSON or parsing fails, return raw text
      return await response.text();
    }
  } catch (error) {
    console.error('Error calling external API:', error);
    throw error;
  }
}

