/**
 * Verifies a JSON Web Token.
 *
 * @param {string} token The JWT string to verify.
 * @returns {object | null} The decoded payload of the token if verification is successful, otherwise null.
 */
function verifyToken(token) {
  try {
    // In a production environment, the secret key should be stored securely,
    // for example, in an environment variable.
    const secret = process.env.JWT_SECRET || 'default-secret-key';
    const decoded = jwt.verify(token, secret);
    return decoded;
  } catch (error) {
    // If the token is invalid (e.g., expired, malformed), jwt.verify will throw an error.
    console.error('Token verification failed:', error.message);
    return null;
  }
}

module.exports = verifyToken;

