 */
function callExternalApi(urlString, apiKey) {
  return new Promise((resolve, reject) => {
    const MAX_RESPONSE_SIZE = 1 * 1024 * 1024; // 1MB

    let parsedUrl;
    try {
      parsedUrl = new URL(urlString);
    } catch (error) {
      return reject(new Error('Invalid URL'));
    }

    if (parsedUrl.protocol !== 'https:') {
      return reject(new Error('Invalid protocol. Only HTTPS is allowed.'));
    }

    const options = {
      method: 'GET',
      headers: {
        'Authorization': `Bearer ${apiKey}`,
        'Content-Type': 'application/json',
        'User-Agent': 'Node.js-Client'
      },
      hostname: parsedUrl.hostname,
      path: `${parsedUrl.pathname}${parsedUrl.search}`
    };

    const req = https.request(options, (res) => {
      let data = '';

      if (res.statusCode < 200 || res.statusCode >= 300) {
        return reject(new Error(`HTTP status code ${res.statusCode}`));
      }

      res.on('data', (chunk) => {
        if (data.length + chunk.length > MAX_RESPONSE_SIZE) {
          res.destroy();
          reject(new Error('Response payload too large'));
        }
        data += chunk;
      });

      res.on('end', () => {
        try {
          const jsonData = JSON.parse(data);
          resolve(jsonData);
        } catch (e) {
          reject(e);
        }
      });
    });

