/**
 * Encrypts a plaintext string using AES-256-CBC.
 * A new, random IV is generated for each encryption.
 * The key must be 32 bytes (256 bits).
 *
 * @param {string} plaintext The string to encrypt.
 * @param {Buffer} key The 32-byte encryption key.
 * @returns {string} A string containing the IV and the encrypted data, separated by a colon, both in hex format.
 */
const encryptSensitiveData = (plaintext, key) => {
  const algorithm = 'aes-256-cbc';
  if (key.length !== 32) {
    throw new Error('Invalid key length. Key must be 32 bytes for AES-256.');
  }

  // Generate a random, unique initialization vector for each encryption
  const iv = crypto.randomBytes(16);

  const cipher = crypto.createCipheriv(algorithm, key, iv);

  let encryptedData = cipher.update(plaintext, 'utf-8', 'hex');
  encryptedData += cipher.final('hex');

  // Prepend the IV to the encrypted data for use in decryption
  return `${iv.toString('hex')}:${encryptedData}`;
};

